import React from 'react';
import Dashboard from './Dashboard';
import './Dashboard.css';

function App() {
  const resumen = {
    totalProductos: 120,
    totalEntradas: 45,
    totalSalidas: 30,
    alertas: 3
  };

  return (
    <div>
      <Dashboard resumen={resumen} />
    </div>
  );
}

export default App;
